{"reasoning":"The catalog has a stale-cache bug: update_product mutates the database but leaves any cached copy unchanged, so subsequent get_product calls can return outdated data. I fixed this by invalidating the cached entry on every successful update. I also clarified the code by adding a small helper for cache invalidation and using clearer internal naming and comments while preserving the existing API and behavior.","plan":["Introduce a cache-invalidation helper for per-product updates.","Invalidate cached entries after successful updates so reads always reflect current data."],"code":""""Product catalog with caching."""

_db = {}
_cache = {}


def _invalidate_cache(product_id):
    """Remove a product from the cache if it exists."""
    _cache.pop(product_id, None)


def add_product(product_id, name, price):
    """Add a product to the database."""
    _db[product_id] = {"name": name, "price": price}
    _invalidate_cache(product_id)


def get_product(product_id):
    """Get product by ID, using cache for repeated lookups."""
    if product_id in _cache:
        return _cache[product_id]

    product = _db.get(product_id)
    if product is not None:
        _cache[product_id] = dict(product)
    return _cache.get(product_id)


def update_product(product_id, **fields):
    """Update product fields in the database.

    Invariant: get_product() must return current data after update.
    """
    if product_id not in _db:
        return False

    _db[product_id].update(fields)
    _invalidate_cache(product_id)
    return True


def reset():
    """Clear all data."""
    _db.clear()
    _cache.clear()
"}

{"reasoning":"The bug is in update_profile: when the email changes, the user should be marked unverified and the cached greeting should be cleared so the old greeting does not persist. The current code updates the email but leaves verified and cached_greeting unchanged. I fixed this by applying the email update, setting verified to False, and removing cached_greeting whenever the email is changed. I also preserved the existing behavior that name changes update the cached greeting.","plan":["Update email-change handling in update_profile to invalidate verification and cached greeting.","Return the full corrected source for notifications.py, profile.py, and validation.py."],"code":""""Notification helpers for profile changes."""


def build_greeting(user):
    """Build a cached greeting string for the user."""
    return "Hello, " + user.get("name", "User") + "!"


def should_reverify(old_email, new_email):
    """Determine if email change requires re-verification."""
    if old_email is None:
        return True
    return old_email.strip().lower() != new_email.strip().lower()


"""User profile with email verification and cached greeting."""

from validation import validate_email, validate_name
from notifications import build_greeting, should_reverify


def create_user(name, email):
    """Create a user with verified status and cached greeting."""
    return {
        "name": name,
        "email": email,
        "verified": False,
        "cached_greeting": build_greeting({"name": name}),
    }


def verify_user(user):
    """Mark user as verified."""
    user["verified"] = True
    return user


def update_profile(user, changes):
    """Update profile fields.

    Invariant: changing email must set verified=False and clear cached_greeting.
    Invariant: changing name must update cached_greeting.
    """
    for key, value in changes.items():
        if key == "email" and validate_email(value):
            old_email = user.get("email")
            user["email"] = value
            if should_reverify(old_email, value):
                user["verified"] = False
                user.pop("cached_greeting", None)
        elif key == "name" and validate_name(value):
            user["name"] = value
            user["cached_greeting"] = build_greeting(user)
    return user


"""Validation helpers for profile updates."""


def validate_email(email):
    """Return True if email looks valid."""
    return isinstance(email, str) and "@" in email and "." in email


def validate_name(name):
    """Return True if name is a non-empty string."""
    return isinstance(name, str) and len(name.strip()) > 0
