{"reasoning":"The deadlock comes from inconsistent lock ordering: A→B acquires A then B, while B→A acquires B then A. Under interleaving, each transfer can hold one lock and wait for the other, creating a circular wait. The fix is to enforce a single global lock order for both transfer directions. I kept the step-based simulation but changed the B→A transfer to acquire A before B as well (matching A→B). This removes the possibility of deadlock under any interleaving because no two operations can hold locks in opposite order.","plan":["Use one consistent global order for all resource acquisitions.","Update the B→A transfer steps to lock A first, then B, mirroring A→B."],"code":""""Resource transfers with lock-ordering deadlock, simulated via steps."""

_locks = {}
_state = {"A": 100, "B": 100}


def reset():
    _locks.clear()
    _state["A"] = 100
    _state["B"] = 100


def acquire(resource):
    """Simulate lock. Raises RuntimeError if already held (deadlock)."""
    if _locks.get(resource):
        raise RuntimeError(f"deadlock: {resource} already locked")
    _locks[resource] = True


def release(resource):
    _locks[resource] = False


def get_state():
    return dict(_state)


def run_steps(steps):
    results = []
    for fn, args in steps:
        results.append(fn(*args))
    return results


def make_transfer_a_to_b_steps(amount):
    """Transfer A→B: lock A first, then B."""

    def step_lock_a():
        acquire("A")
        return "locked_A"

    def step_lock_b_and_transfer():
        acquire("B")
        _state["A"] -= amount
        _state["B"] += amount
        release("B")
        release("A")
        return "transferred_a_to_b"

    return step_lock_a, step_lock_b_and_transfer


def make_transfer_b_to_a_steps(amount):
    """Transfer B→A: fixed — lock A first, then B to match global order."""

    def step_lock_a():
        acquire("A")
        return "locked_A"

    def step_lock_b_and_transfer():
        acquire("B")
        _state["B"] -= amount
        _state["A"] += amount
        release("B")
        release("A")
        return "transferred_b_to_a"

    return step_lock_a, step_lock_b_and_transfer


def sequential_transfers():
    """A→B then B→A. Sequential: works fine."""
    reset()
    lock_ab, do_ab = make_transfer_a_to_b_steps(10)
    lock_ba, do_ba = make_transfer_b_to_a_steps(10)
    run_steps([
        (lock_ab, ()), (do_ab, ()),
        (lock_ba, ()), (do_ba, ()),
    ])
    return get_state()


def interleaved_transfers():
    """A→B and B→A interleaved: no deadlock with consistent lock ordering."""
    reset()
    lock_ab, do_ab = make_transfer_a_to_b_steps(10)
    lock_ba, do_ba = make_transfer_b_to_a_steps(10)
    try:
        run_steps([
            (lock_ab, ()),   # A→B locks A
            (lock_ba, ()),   # B→A tries to lock A too; simulation raises if already locked
            (do_ab, ()),
            (do_ba, ()),
        ])
        return get_state()
    except RuntimeError as e:
        return {"error": str(e)}
